mapper.select:
SELECT DATE(r.confirmed_at) AS sale_date, COUNT(*) AS ticket_count, SUM(r.amount) AS total_amount FROM reservation r JOIN seat s ON s.id = r.seat_id JOIN performance_schedule ps ON ps.id = s.schedule_id WHERE r.status = 'CONFIRMED'
AND r.confirmed_at >= #{from}
AND r.confirmed_at < DATE_ADD(#{to}, INTERVAL 1 DAY)
AND ps.performance_id = #{performanceId}
GROUP BY DATE(r.confirmed_at) ORDER BY sale_date ASC
